<script lang="ts">import type{Persona}from'@simbot/risu';let{personas,active,bound,onselect,onsave,onnew,onclone,onremove,onbind}:{personas:Persona[];active:Persona;bound:boolean;onselect:(id:string)=>void;onsave:(p:Persona)=>void;onnew:()=>void;onclone:()=>void;onremove:()=>void;onbind:(v:boolean)=>void}=$props();async function icon(file:File){const img=new Image(),url=URL.createObjectURL(file);await new Promise<void>((ok,fail)=>{img.onload=()=>ok();img.onerror=fail;img.src=url;});const scale=Math.min(1,128/Math.max(img.width,img.height)),canvas=document.createElement('canvas');canvas.width=Math.max(1,Math.round(img.width*scale));canvas.height=Math.max(1,Math.round(img.height*scale));canvas.getContext('2d')!.drawImage(img,0,0,canvas.width,canvas.height);URL.revokeObjectURL(url);onsave({...active,icon:canvas.toDataURL('image/webp',.85)});}</script>
<section><select value={active.id} onchange={(e)=>onselect(e.currentTarget.value)}>{#each personas as p}<option value={p.id}>{p.name}</option>{/each}</select><div class="buttons"><button onclick={onnew}>＋ 새 페르소나</button><button onclick={onclone}>복제</button><button onclick={onremove}>삭제</button></div>{#if active.icon}<img src={active.icon} alt=""/>{/if}<label>아이콘<input type="file" accept="image/*" onchange={(e)=>{const f=e.currentTarget.files?.[0];if(f)void icon(f);}}/></label><label>이름<input value={active.name} oninput={(e)=>onsave({...active,name:e.currentTarget.value})}/></label><label>설명<textarea rows="8" value={active.prompt} oninput={(e)=>onsave({...active,prompt:e.currentTarget.value})}></textarea></label><label class="bind"><input type="checkbox" checked={bound} onchange={(e)=>onbind(e.currentTarget.checked)}/> 이 카드에 이 페르소나 고정</label></section>
<style>section{display:grid;gap:8px}.buttons{display:flex;gap:4px}label{display:grid;gap:3px;font-size:11px}input,select,textarea,button{background:#12151b;color:#ddd;border:1px solid #3b414d;border-radius:5px;padding:6px}img{width:72px;height:72px;object-fit:cover;border-radius:8px}.bind{display:flex;align-items:center}</style>
